package testutils.ptest2.org.apache.hive.ptest.execution;

public class Drone { private final String privateKey ; private final String user ; private final String host ; private final int instance ; private final String localDir ; public Drone ( String privateKey , String user , String host , int instance , String localDir ) { this . privateKey = privateKey ; this . user = user ; this . host = host ; this . instance = instance ; this . localDir = localDir ; } public String getPrivateKey ( ) { return privateKey ; } public String getUser ( ) { return user ; } public String getHost ( ) { return host ; } @ Override public String toString ( ) { return "Drone [user=" + user + ", host=" + host + ", instance=" + instance + "]" ; } public String getLocalDirectory ( ) { return localDir ; } public String getLocalLogDirectory ( ) { return ( new File ( new File ( localDir , getInstanceName ( ) ) , "logs" ) ) . getAbsolutePath ( ) ; } public String getInstanceName ( ) { return String . format ( "%s-%s-%d" , host , user , instance ) ; } public int getInstance ( ) { return instance ; } }